import type { Exchange } from "@urql/core";
import { fromPromise, fromValue, mergeMap, pipe } from "wonka";
import type { TokenBucket } from "./support.js";

export const rateLimitExchange = (bucket: TokenBucket): Exchange => {
  return ({ forward }) => {
    return (ops$) => {
      return pipe(
        ops$,
        mergeMap((operation) => {
          if (operation.kind === "teardown") {
            return fromValue(operation);
          }
          return fromPromise(bucket.consume().then(() => operation));
        }),
        forward
      );
    };
  };
};
